import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

const COLORS = ['#1a56db','#10b981','#f59e0b','#ef4444','#6366f1','#06b6d4','#ec4899','#8b5cf6'];

export default function AdminDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/admin/stats').then(res => { setData(res.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data) return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load stats</div></div>;

  const { stats, studentsByDept, studentsBySem } = data;

  const semData = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const deptData = studentsByDept.map(d => ({ name: d.deptName || 'Unknown', value: d.count }));

  return (
    <div>
      <div className="stats-grid">
        <div className="stat-card blue"><div className="stat-icon">👨‍🎓</div><div><div className="stat-value">{stats.totalStudents}</div><div className="stat-label">Total Students</div></div></div>
        <div className="stat-card green"><div className="stat-icon">👩‍🏫</div><div><div className="stat-value">{stats.totalFaculty}</div><div className="stat-label">Faculty Members</div></div></div>
        <div className="stat-card purple"><div className="stat-icon">🧑‍💼</div><div><div className="stat-value">{stats.totalHods}</div><div className="stat-label">HODs</div></div></div>
        <div className="stat-card yellow"><div className="stat-icon">🏢</div><div><div className="stat-value">{stats.totalDepartments}</div><div className="stat-label">Departments</div></div></div>
        <div className="stat-card cyan"><div className="stat-icon">📚</div><div><div className="stat-value">{stats.totalSubjects}</div><div className="stat-label">Subjects</div></div></div>
        <div className="stat-card red"><div className="stat-icon">📊</div><div><div className="stat-value">{stats.totalMarksEntries}</div><div className="stat-label">Marks Entries</div></div></div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        <div className="card">
          <div className="card-header"><span className="card-title">Students by Semester</span></div>
          <div className="card-body">
            {semData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={semData}><XAxis dataKey="name" tick={{ fontSize: 12 }} /><YAxis allowDecimals={false} /><Tooltip /><Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]} /></BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No student data</div></div>}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><span className="card-title">Students by Department</span></div>
          <div className="card-body">
            {deptData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart><Pie data={deptData} cx="50%" cy="50%" outerRadius={90} dataKey="value" label={({ name, value }) => `${name}: ${value}`} labelLine={false}>
                    {deptData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Pie><Tooltip /><Legend /></PieChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No department data</div></div>}
          </div>
        </div>
      </div>
    </div>
  );
}
